    pq.push([0, 0, 0]); // (cost, node, hasSwitchUsed)
    const dist: number[][] = new Array(n).fill(0).map(() => new Array(2).fill(Infinity));
    dist[0][0] = 0;

    while (pq.length > 0) {
        const [cost, node, usedSwitch] = pq.shift() as [number, number, number];
        if (node === n - 1) return cost;
        if (cost > dist[node][usedSwitch]) continue;

        // Traverse original edges
        for (const [v, w] of adj[node]) {
            if (dist[node][usedSwitch] + w < dist[v][usedSwitch]) {
                dist[v][usedSwitch] = dist[node][usedSwitch] + w;
                pq.push([dist[v][usedSwitch], v, usedSwitch]);
            }
