            // We need to find the incoming edge to this node
            // Since we are using Dijkstra's, we can't directly track the incoming edge
            // So we simulate flipping by considering the reverse edge
            // This is a bit tricky, but we can simulate it by adding a virtual edge
            // with cost 2 * w for the reverse direction
            // However, since we don't have the original edge, we need to track it
            // So we need to track the incoming edges to each node
            // Let's build an incoming edges list
            const incoming: number[][] = new Array(n).fill(0).map(() => []);
            for (const [u, v, w] of edges) {
                incoming[v].push([u, w]);
            }

            for (const [u, w] of incoming[node]) {
                if (dist[node][usedSwitch] + 2 * w < dist[u][1]) {
                    dist[u][1] = dist[node][usedSwitch] + 2 * w;
                    pq.push([dist[u][1], u, 1]);
                }
            }
        }
    }

